// HasAgent applies the HasEdge predicate on the "agent" edge.
func HasAgent() predicate.NanoMDMInfo {
	return predicate.NanoMDMInfo(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.O2O, true, AgentTable, AgentColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasAgentWith applies the HasEdge predicate on the "agent" edge with a given conditions (other predicates).
func HasAgentWith(preds ...predicate.Agent) predicate.NanoMDMInfo {
	return predicate.NanoMDMInfo(func(s *sql.Selector) {
		step := newAgentStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.NanoMDMInfo) predicate.NanoMDMInfo {
	return predicate.NanoMDMInfo(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.NanoMDMInfo) predicate.NanoMDMInfo {
	return predicate.NanoMDMInfo(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.NanoMDMInfo) predicate.NanoMDMInfo {
	return predicate.NanoMDMInfo(sql.NotPredicates(p))
}
